"""JSON-file persistence for cedardonation — one list of donation records."""

import json
from pathlib import Path

DEFAULT_PATH = Path("donations.json")


def load_records(path=DEFAULT_PATH):
    """Return the stored donation records (empty list when no file)."""
    path = Path(path)
    if not path.exists():
        return []
    return json.loads(path.read_text(encoding="utf-8"))


def save_records(records, path=DEFAULT_PATH):
    """Write the donation records back to disk."""
    Path(path).write_text(json.dumps(records, indent=2), encoding="utf-8")

"""Core operations over donation records."""

import math


def add_record(records, category, amount, note=""):
    """Append a donation record and return it.

    Raises ``ValueError`` for a blank category or a non-finite amount.
    """
    category = category.strip()
    if not category:
        raise ValueError("category must not be empty")
    amount = float(amount)
    if not math.isfinite(amount):
        raise ValueError("amount must be a finite number")
    record = {
        "category": category,
        "amount": amount,
        "note": note,
    }
    records.append(record)
    return record


def total_amount(records):
    """Sum the amount field across records."""
    return sum(r["amount"] for r in records)


def filter_by_category(records, category):
    """Return records whose category matches (case-insensitive)."""
    if not category.strip():
        raise ValueError("category must not be empty")
    return [r for r in records if r["category"] == category]


def top_categories(records, limit=3):
    """Return the ``limit`` categories with the highest summed amount."""
    if limit <= 0:
        raise ValueError("limit must be a positive integer")
    totals = {}
    for r in records:
        totals[r["category"]] = totals.get(r["category"], 0.0) + r["amount"]
    ranked = sorted(totals.items(), key=lambda kv: (-kv[1], kv[0]))
    return ranked[:limit]


def report(records):
    """Return per-category (count, total) stats, sorted by total highest first."""
    stats = {}
    for r in records:
        count, total = stats.get(r["category"], (0, 0.0))
        stats[r["category"]] = (count + 1, total + r["amount"])
    ranked = sorted(stats.items(), key=lambda kv: (-kv[1][1], kv[0]))
    return [(category, count, total) for category, (count, total) in ranked]

"""Tests for cedardonation core operations."""

import pytest

from cedardonation import ops


def _sample():
    records = []
    ops.add_record(records, "food", 12.5, "lunch")
    ops.add_record(records, "travel", 30.0)
    ops.add_record(records, "food", 7.5)
    return records


def test_add_record_appends():
    records = _sample()
    assert len(records) == 3


def test_add_record_returns_record():
    records = []
    record = ops.add_record(records, "misc", 1.0, "x")
    assert record["category"] == "misc"


def test_total_amount():
    assert ops.total_amount(_sample()) == 50.0


def test_filter_by_category_exact():
    assert len(ops.filter_by_category(_sample(), "food")) == 2


def test_top_categories_ranked():
    ranked = ops.top_categories(_sample())
    assert ranked[0] == ("travel", 30.0)


def test_top_categories_limit():
    assert len(ops.top_categories(_sample(), limit=1)) == 1


def test_top_categories_rejects_non_positive_limit():
    with pytest.raises(ValueError):
        ops.top_categories(_sample(), limit=0)


def test_report_sorted_by_total():
    assert ops.report(_sample()) == [
        ("travel", 1, 30.0),
        ("food", 2, 20.0),
    ]


def test_report_empty():
    assert ops.report([]) == []


def test_add_record_rejects_blank_category():
    with pytest.raises(ValueError):
        ops.add_record([], "   ", 5.0)


def test_add_record_rejects_non_finite_amount():
    with pytest.raises(ValueError):
        ops.add_record([], "food", float("nan"))


def test_add_record_strips_category_whitespace():
    records = []
    ops.add_record(records, "  food  ", 5.0)
    assert records[0]["category"] == "food"


def test_filter_by_category_rejects_blank_category():
    with pytest.raises(ValueError):
        ops.filter_by_category(_sample(), "   ")

